using SiteInspector.Models;

namespace SiteInspector.Services;

public interface ILocalStorageService
{
    Task<List<InspectionSite>> GetSitesAsync();
    Task SaveSiteAsync(InspectionSite site);
    Task DeleteSiteAsync(string siteId);

    Task<List<InspectionReport>> GetReportsAsync(string? siteId = null);
    Task<InspectionReport?> GetReportAsync(string reportId);
    Task SaveReportAsync(InspectionReport report);
    Task DeleteReportAsync(string reportId);

    Task<List<InspectionReport>> GetPendingSyncReportsAsync();
    Task MarkReportSyncedAsync(string reportId);
}

using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class IndexedDbStorageService : ILocalStorageService
{
    private readonly IJSRuntime _js;

    public IndexedDbStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task<List<InspectionSite>> GetSitesAsync()
    {
        var json = await _js.InvokeAsync<string>("db.getAll", "sites");
        return string.IsNullOrEmpty(json)
            ? new List<InspectionSite>()
            : JsonSerializer.Deserialize<List<InspectionSite>>(json) ?? new();
    }

    public async Task SaveSiteAsync(InspectionSite site)
    {
        var json = JsonSerializer.Serialize(site);
        await _js.InvokeVoidAsync("db.put", "sites", site.Id, json);
    }

    public async Task DeleteSiteAsync(string siteId)
    {
        await _js.InvokeVoidAsync("db.delete", "sites", siteId);
    }

    public async Task<List<InspectionReport>> GetReportsAsync(string? siteId = null)
    {
        var json = await _js.InvokeAsync<string>("db.getAll", "reports");
        var reports = string.IsNullOrEmpty(json)
            ? new List<InspectionReport>()
            : JsonSerializer.Deserialize<List<InspectionReport>>(json) ?? new();

        if (!string.IsNullOrEmpty(siteId))
            reports = reports.Where(r => r.SiteId == siteId).ToList();

        return reports.OrderByDescending(r => r.InspectionDate).ToList();
    }

    public async Task<InspectionReport?> GetReportAsync(string reportId)
    {
        var json = await _js.InvokeAsync<string>("db.get", "reports", reportId);
        return string.IsNullOrEmpty(json) ? null : JsonSerializer.Deserialize<InspectionReport>(json);
    }

    public async Task SaveReportAsync(InspectionReport report)
    {
        report.LastModified = DateTime.UtcNow;
        var json = JsonSerializer.Serialize(report);
        await _js.InvokeVoidAsync("db.put", "reports", report.Id, json);
    }

    public async Task DeleteReportAsync(string reportId)
    {
        await _js.InvokeVoidAsync("db.delete", "reports", reportId);
    }

    public async Task<List<InspectionReport>> GetPendingSyncReportsAsync()
    {
        var reports = await GetReportsAsync();
        return reports.Where(r => r.SyncStatus == SyncStatus.Pending).ToList();
    }

    public async Task MarkReportSyncedAsync(string reportId)
    {
        var report = await GetReportAsync(reportId);
        if (report != null)
        {
            report.SyncStatus = SyncStatus.Synced;
            await SaveReportAsync(report);
        }
    }
}

using System.Net.Http.Json;
using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly ILocalStorageService _storage;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private Timer? _timer;

    public event Action<bool>? OnConnectivityChanged;
    public event Action<int>? OnSyncProgress;
    public bool IsOnline { get; private set; }
    public int PendingCount { get; private set; }

    public SyncService(ILocalStorageService storage, HttpClient http, IJSRuntime js)
    {
        _storage = storage;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        IsOnline = await _js.InvokeAsync<bool>("navigator.onLine.valueOf");
        await UpdatePendingCount();
        _timer = new Timer(async _ => await TrySync(), null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(30));
    }

    public async Task TrySync()
    {
        try
        {
            IsOnline = await _js.InvokeAsync<bool>("navigator.onLine.valueOf");
            OnConnectivityChanged?.Invoke(IsOnline);

            if (!IsOnline) return;

            var pending = await _storage.GetPendingSyncReportsAsync();
            PendingCount = pending.Count;
            OnSyncProgress?.Invoke(PendingCount);

            foreach (var report in pending)
            {
                try
                {
                    // Attempt to sync to server API
                    var response = await _http.PostAsJsonAsync("api/inspections/sync", report);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkReportSyncedAsync(report.Id);
                        PendingCount--;
                        OnSyncProgress?.Invoke(PendingCount);
                    }
                }
                catch
                {
                    // Server unavailable — will retry on next cycle
                }
            }
        }
        catch
        {
            // Connectivity check failed — offline
            IsOnline = false;
            OnConnectivityChanged?.Invoke(false);
        }
    }

    private async Task UpdatePendingCount()
    {
        var pending = await _storage.GetPendingSyncReportsAsync();
        PendingCount = pending.Count;
    }

    public void Dispose()
    {
        _timer?.Dispose();
    }
}

const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let dbInstance = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (dbInstance) { resolve(dbInstance); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const db = e.target.result;
            if (!db.objectStoreNames.contains('sites')) {
                db.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!db.objectStoreNames.contains('reports')) {
                db.createObjectStore('reports', { keyPath: 'id' });
            }
        };
        request.onsuccess = (e) => {
            dbInstance = e.target.result;
            resolve(dbInstance);
        };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.db = {
    async put(storeName, key, jsonValue) {
        const db = await openDb();
        const tx = db.transaction(storeName, 'readwrite');
        const store = tx.objectStore(storeName);
        const obj = JSON.parse(jsonValue);
        obj.id = key;
        store.put(obj);
        return new Promise((resolve, reject) => {
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    async get(storeName, key) {
        const db = await openDb();
        const tx = db.transaction(storeName, 'readonly');
        const store = tx.objectStore(storeName);
        const request = store.get(key);
        return new Promise((resolve, reject) => {
            request.onsuccess = () => {
                resolve(request.result ? JSON.stringify(request.result) : null);
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    async getAll(storeName) {
        const db = await openDb();
        const tx = db.transaction(storeName, 'readonly');
        const store = tx.objectStore(storeName);
        const request = store.getAll();
        return new Promise((resolve, reject) => {
            request.onsuccess = () => {
                resolve(JSON.stringify(request.result || []));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    async delete(storeName, key) {
        const db = await openDb();
        const tx = db.transaction(storeName, 'readwrite');
        const store = tx.objectStore(storeName);
        store.delete(key);
        return new Promise((resolve, reject) => {
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    }
};

window.camera = {
    capturePhoto: function (inputElementId) {
        return new Promise((resolve) => {
            const input = document.getElementById(inputElementId);
            if (!input) { resolve(null); return; }

            input.onchange = (e) => {
                const file = e.target.files[0];
                if (!file) { resolve(null); return; }

                const reader = new FileReader();
                reader.onload = () => {
                    // Compress image for storage efficiency
                    const img = new Image();
                    img.onload = () => {
                        const canvas = document.createElement('canvas');
                        const maxDim = 1200;
                        let w = img.width, h = img.height;
                        if (w > maxDim || h > maxDim) {
                            if (w > h) { h = h * maxDim / w; w = maxDim; }
                            else { w = w * maxDim / h; h = maxDim; }
                        }
                        canvas.width = w;
                        canvas.height = h;
                        canvas.getContext('2d').drawImage(img, 0, 0, w, h);
                        const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
                        const base64 = dataUrl.split(',')[1];
                        resolve(base64);
                    };
                    img.src = reader.result;
                };
                reader.readAsDataURL(file);
            };
            input.click();
        });
    }
};

const CACHE_NAME = 'site-inspector-v1';
const ASSETS_TO_CACHE = [
    '/',
    '/index.html',
    '/css/app.css',
    '/js/indexeddb.js',
    '/js/camera.js',
    '/manifest.json',
    '/icon-192.png'
];

self.addEventListener('install', event => {
    event.waitUntil(
        caches.open(CACHE_NAME).then(cache => {
            return cache.addAll(ASSETS_TO_CACHE);
        }).then(() => self.skipWaiting())
    );
});

self.addEventListener('activate', event => {
    event.waitUntil(
        caches.keys().then(keys =>
            Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
        ).then(() => self.clients.claim())
    );
});

self.addEventListener('fetch', event => {
    // Skip non-GET requests and API calls
    if (event.request.method !== 'GET') return;
    if (event.request.url.includes('/api/')) return;

    event.respondWith(
        caches.match(event.request).then(cached => {
            if (cached) return cached;

            return fetch(event.request).then(response => {
                if (!response || response.status !== 200) return response;

                const responseClone = response.clone();
                caches.open(CACHE_NAME).then(cache => {
                    cache.put(event.request, responseClone);
                });
                return response;
            }).catch(() => {
                // Return offline fallback for navigation
                if (event.request.mode === 'navigate') {
                    return caches.match('/index.html');
                }
                return new Response('', { status: 503, statusText: 'Offline' });
            });
        })
    );
});

