arguments.new_str:
@inherits LayoutComponentBase
@inject SiteInspector.Services.SyncService SyncService

<div class="app-container">
    <header class="app-header">
        <h1>🏗️ Site Inspector</h1>
        <div class="sync-status">
            @if (SyncService.IsOnline)
            {
                <span class="status-dot online"></span>
                <span>Online</span>
            }
            else
            {
                <span class="status-dot offline"></span>
                <span>Offline</span>
            }
            @if (SyncService.PendingCount > 0)
            {
                <span class="pending-badge">@SyncService.PendingCount pending</span>
            }
        </div>
    </header>

    <main class="app-main">
        @Body
    </main>
</div>

@code {
    protected override void OnInitialized()
    {
        SyncService.OnConnectivityChanged += _ => InvokeAsync(StateHasChanged);
        SyncService.OnSyncProgress += _ => InvokeAsync(StateHasChanged);
    }
}

