@page "/"
@inject SiteInspector.Services.ILocalStorageService Storage
@inject NavigationManager Navigation

<div class="page-content">
    <div class="section-header">
        <h2>Construction Sites</h2>
        <button class="btn-primary" @onclick="ShowAddSite">+ Add Site</button>
    </div>

    @if (_showAddForm)
    {
        <div class="card add-form">
            <input @bind="_newSiteName" @bind:event="oninput" placeholder="Site name" class="input-field" />
            <input @bind="_newSiteAddress" @bind:event="oninput" placeholder="Address" class="input-field" />
            <div class="form-actions">
                <button class="btn-primary" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">Save</button>
                <button class="btn-secondary" @onclick="() => _showAddForm = false">Cancel</button>
            </div>
        </div>
    }

    @if (_sites.Count == 0 && !_showAddForm)
    {
        <div class="empty-state">
            <p>No sites yet. Tap <strong>+ Add Site</strong> to get started.</p>
        </div>
    }

    <div class="site-list">
        @foreach (var site in _sites)
        {
            <div class="card site-card" @onclick="() => NavigateToSite(site.Id)">
                <div class="site-info">
                    <h3>@site.Name</h3>
                    <p>@site.Address</p>
                </div>
                <span class="chevron">›</span>
            </div>
        }
    </div>
