    {
        var base64 = await JS.InvokeAsync<string?>("camera.capturePhoto", "photoInput");
        if (!string.IsNullOrEmpty(base64))
        {
            _report.Photos.Add(new SiteInspector.Models.PhotoAttachment
            {
                DataBase64 = base64,
                FileName = $"photo_{DateTime.Now:yyyyMMdd_HHmmss}.jpg"
            });
        }
