@inject SiteInspector.Services.ILocalStorageService Storage
@inject NavigationManager Navigation
@inject Microsoft.JSInterop.IJSRuntime JS

<div class="page-content inspection-page">
    <div class="inspection-header">
        <button class="btn-back" @onclick="GoBack">← Back</button>
        <button class="btn-primary btn-save" @onclick="SaveReport">💾 Save</button>
    </div>

    <div class="inspector-field">
        <input @bind="_report.InspectorName" @bind:event="oninput" placeholder="Inspector name" class="input-field" />
    </div>

    <!-- Tab Navigation -->
    <div class="tab-bar">
        <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
            Checklist (@CompletedCount/@_report.Checklist.Count)
        </button>
        <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
            Photos (@_report.Photos.Count)
        </button>
        <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
            Notes
        </button>
    </div>

    @if (_activeTab == "checklist")
    {
        <div class="checklist-container">
            @foreach (var category in _report.Checklist.GroupBy(c => c.Category))
            {
                <div class="category-group">
                    <h3 class="category-title">@category.Key</h3>
                    @foreach (var item in category)
                    {
                        <div class="checklist-item @GetItemClass(item)">
                            <div class="item-description">@item.Description</div>
                            <div class="item-actions">
                                <button class="result-btn pass @(item.Result == SiteInspector.Models.CheckResult.Pass ? "selected" : "")"
                                        @onclick="() => SetResult(item, SiteInspector.Models.CheckResult.Pass)"
                                        @onclick:stopPropagation="true">✓</button>
                                <button class="result-btn fail @(item.Result == SiteInspector.Models.CheckResult.Fail ? "selected" : "")"
                                        @onclick="() => SetResult(item, SiteInspector.Models.CheckResult.Fail)"
                                        @onclick:stopPropagation="true">✗</button>
                                <button class="result-btn attention @(item.Result == SiteInspector.Models.CheckResult.NeedsAttention ? "selected" : "")"
                                        @onclick="() => SetResult(item, SiteInspector.Models.CheckResult.NeedsAttention)"
                                        @onclick:stopPropagation="true">⚠</button>
                            </div>
                            @if (item.Result == SiteInspector.Models.CheckResult.Fail || item.Result == SiteInspector.Models.CheckResult.NeedsAttention)
                            {
                                <input @bind="item.Notes" @bind:event="oninput" placeholder="Add note..."
                                       class="item-note" />
                            }
                        </div>
                    }
                </div>
            }
        </div>
    }
    else if (_activeTab == "photos")
    {
        <div class="photos-container">
            <button class="btn-primary btn-capture" @onclick="CapturePhoto">📷 Take Photo</button>

            @if (_report.Photos.Count == 0)
            {
                <div class="empty-state">
                    <p>No photos attached yet.</p>
                </div>
            }

            <div class="photo-grid">
                @foreach (var photo in _report.Photos)
                {
                    <div class="photo-card">
                        <img src="data:image/jpeg;base64,@photo.DataBase64" alt="@photo.Caption" />
                        <input @bind="photo.Caption" @bind:event="oninput" placeholder="Caption..."
                               class="photo-caption" />
                        <button class="btn-delete-photo" @onclick="() => RemovePhoto(photo)">🗑️</button>
                    </div>
                }
            </div>
        </div>
    }
    else if (_activeTab == "notes")
    {
        <div class="notes-container">
            <textarea @bind="_report.Notes" @bind:event="oninput" placeholder="General inspection notes..."
                      class="notes-textarea"></textarea>
        </div>
    }
</div>

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private SiteInspector.Models.InspectionReport _report = new();
    private string _activeTab = "checklist";

    private int CompletedCount => _report.Checklist.Count(c => c.Result != SiteInspector.Models.CheckResult.NotInspected);

    protected override void OnInitialized()
    {
        _report = new SiteInspector.Models.InspectionReport
        {
            SiteId = SiteId,
            Checklist = SiteInspector.Models.ChecklistTemplates.GetStandardChecklist()
        };
    }

    private void SetResult(SiteInspector.Models.ChecklistItem item, SiteInspector.Models.CheckResult result)
    {
        item.Result = item.Result == result ? SiteInspector.Models.CheckResult.NotInspected : result;
    }

    private string GetItemClass(SiteInspector.Models.ChecklistItem item) => item.Result switch
    {
        SiteInspector.Models.CheckResult.Pass => "item-pass",
        SiteInspector.Models.CheckResult.Fail => "item-fail",
        SiteInspector.Models.CheckResult.NeedsAttention => "item-attention",
        _ => ""
    };

    private async Task CapturePhoto()
    {
        var base64 = await JS.InvokeAsync<string?>("camera.capturePhoto", "photoInput");
        if (!string.IsNullOrEmpty(base64))
        {
            _report.Photos.Add(new SiteInspector.Models.PhotoAttachment
            {
                DataBase64 = base64,
                FileName = $"photo_{DateTime.Now:yyyyMMdd_HHmmss}.jpg"
            });
        }
    }

    private void RemovePhoto(SiteInspector.Models.PhotoAttachment photo)
    {
        _report.Photos.Remove(photo);
    }

    private async Task SaveReport()
    {
        await Storage.SaveReportAsync(_report);
        Navigation.NavigateTo($"/site/{SiteId}");
    }

    private void GoBack()
    {
        Navigation.NavigateTo($"/site/{SiteId}");
    }
}
