@page "/site/{SiteId}"
@inject SiteInspector.Services.ILocalStorageService Storage
@inject NavigationManager Navigation

<div class="page-content">
    <button class="btn-back" @onclick='() => Navigation.NavigateTo("/")'>← Back</button>

    @if (_site != null)
    {
        <div class="section-header">
            <div>
                <h2>@_site.Name</h2>
                <p class="subtitle">@_site.Address</p>
            </div>
            <button class="btn-primary" @onclick="StartNewInspection">+ New Inspection</button>
        </div>
    }

    <h3 class="list-title">Inspection History</h3>

    @if (_reports.Count == 0)
    {
        <div class="empty-state">
            <p>No inspections yet for this site.</p>
        </div>
    }

    <div class="report-list">
        @foreach (var report in _reports)
        {
            <div class="card report-card" @onclick="() => NavigateToReport(report.Id)">
                <div class="report-info">
                    <div class="report-date">@report.InspectionDate.ToString("MMM dd, yyyy h:mm tt")</div>
                    <div class="report-inspector">@report.InspectorName</div>
                    <div class="report-stats">
                        <span class="stat pass">✓ @report.Checklist.Count(c => c.Result == SiteInspector.Models.CheckResult.Pass)</span>
                        <span class="stat fail">✗ @report.Checklist.Count(c => c.Result == SiteInspector.Models.CheckResult.Fail)</span>
                        <span class="stat photos">📷 @report.Photos.Count</span>
                    </div>
                </div>
                <div class="report-sync">
                    @if (report.SyncStatus == SiteInspector.Models.SyncStatus.Synced)
                    {
                        <span class="sync-badge synced">✓ Synced</span>
                    }
                    else
                    {
                        <span class="sync-badge pending">⏳ Pending</span>
                    }
                </div>
            </div>
        }
    </div>
</div>

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private SiteInspector.Models.InspectionSite? _site;
    private List<SiteInspector.Models.InspectionReport> _reports = new();

    protected override async Task OnInitializedAsync()
    {
        var sites = await Storage.GetSitesAsync();
        _site = sites.FirstOrDefault(s => s.Id == SiteId);
        _reports = await Storage.GetReportsAsync(SiteId);
    }

    private void StartNewInspection()
    {
        Navigation.NavigateTo($"/inspect/{SiteId}");
    }

    private void NavigateToReport(string reportId)
    {
        Navigation.NavigateTo($"/report/{reportId}");
    }
}

