    cursor: pointer;
    touch-action: manipulation;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.15s;
}

.result-btn:active {
    transform: scale(0.9);
}

.result-btn.pass.selected {
    background: var(--success);
    border-color: var(--success);
    color: white;
}

.result-btn.fail.selected {
    background: var(--danger);
    border-color: var(--danger);
    color: white;
}

.result-btn.attention.selected {
    background: var(--warning);
    border-color: var(--warning);
    color: white;
}

.item-note {
    width: 100%;
    margin-top: 8px;
    padding: 10px 12px;
    border: 1px solid var(--border);
    border-radius: 8px;
    font-size: 0.85rem;
    outline: none;
}

.item-note:focus {
    border-color: var(--primary);
}

/* Photos */
.photos-container {
    padding-bottom: 80px;
}

.btn-capture {
    width: 100%;
    padding: 16px;
    font-size: 1.1rem;
    margin-bottom: 16px;
}

.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
    gap: 12px;
}

.photo-card {
    background: var(--surface);
    border-radius: var(--radius);
    overflow: hidden;
    box-shadow: var(--shadow);
    position: relative;
}

.photo-card img {
    width: 100%;
    height: 150px;
    object-fit: cover;
}

.photo-caption {
    width: 100%;
    padding: 8px 12px;
    border: none;
    border-top: 1px solid var(--border);
    font-size: 0.8rem;
    outline: none;
}

.photo-caption-display {
    padding: 8px 12px;
    font-size: 0.8rem;
    color: var(--text-light);
}

.btn-delete-photo {
    position: absolute;
    top: 6px;
    right: 6px;
    background: rgba(0,0,0,0.6);
    border: none;
    border-radius: 50%;
    width: 30px;
    height: 30px;
    font-size: 0.8rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
}

/* Notes */
.notes-container {
    padding-bottom: 80px;
}

.notes-textarea {
    width: 100%;
    min-height: 300px;
    padding: 16px;
    border: 2px solid var(--border);
    border-radius: var(--radius);
    font-size: 1rem;
    font-family: inherit;
    resize: vertical;
    outline: none;
    line-height: 1.6;
}

.notes-textarea:focus {
    border-color: var(--primary);
}

.notes-display {
    white-space: pre-wrap;
    line-height: 1.6;
}

/* Report Detail */
.report-detail-header {
    margin-bottom: 20px;
}

.report-detail-header h2 {
    margin: 0;
}

.report-summary {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 8px;
    margin-bottom: 20px;
}

.summary-stat {
    background: var(--surface);
    border-radius: var(--radius);
    padding: 12px 8px;
    text-align: center;
    box-shadow: var(--shadow);
}

.summary-stat.pass { border-top: 3px solid var(--success); }
.summary-stat.fail { border-top: 3px solid var(--danger); }
.summary-stat.attention { border-top: 3px solid var(--warning); }
.summary-stat.neutral { border-top: 3px solid var(--border); }

.stat-number {
    display: block;
    font-size: 1.5rem;
    font-weight: 700;
}

.stat-label {
    font-size: 0.7rem;
    color: var(--text-light);
    text-transform: uppercase;
}

/* Issue Cards */
.issue-card {
    border-left: 4px solid var(--danger);
}

.issue-card.issue-attention {
    border-left-color: var(--warning);
}

.issue-category {
    font-size: 0.75rem;
    font-weight: 700;
    text-transform: uppercase;
    color: var(--text-light);
}

.issue-desc {
    font-weight: 600;
    margin: 4px 0;
}

.issue-notes {
    font-size: 0.85rem;
    color: var(--text-light);
    margin-top: 4px;
}

/* Empty State */
.empty-state {
    text-align: center;
    padding: 40px 20px;
    color: var(--text-light);
}

/* Loading */
.loading-screen {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    height: 100dvh;
    gap: 16px;
}

.loading-spinner {
    width: 40px;
    height: 40px;
    border: 4px solid var(--border);
    border-top-color: var(--primary);
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

/* Save button fixed */
.btn-save {
    position: relative;
}

/* Responsive */
@media (min-width: 768px) {
    .page-content {
        padding: 24px;
    }

    .photo-grid {
        grid-template-columns: repeat(3, 1fr);
    }
}

